#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e3 + 5;
int n, k, f[MAXN][MAXN], a[MAXN];
int main(void)
{
	cin >> n >> k;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
	}
	for (int i = 1; i <= n; ++i)
	{
		f[i][0] = f[i - 1][0] + ( 1 == a[i]);
	}
	for (int i = 1; i <= n; ++i)//动态规划DP
	{
		for (int j = 1; j <= k; ++j)
		{
			f[i][j] = max(f[i - 1][j], f[i - 1][j - 1]) + (j % 2 + 1 == a[i]);
		}
	}
	int ans = 0;
	for (int i = 0; i <= k; ++i)
	{
		ans = max(ans, f[n][i]);
	}
	cout << ans;
	return false;
}
